mapper.select:
SELECT tFile.file_id, tFile.serial_number, mUser.user_name, mUser.post_id, tFile.title, tFile.date, tFile.file_name, tFile.version FROM t_file tFile LEFT OUTER JOIN t_join_user tJoinUser ON tFile.file_id = tJoinUser.file_id LEFT OUTER JOIN m_user mUser ON tJoinUser.user_id = mUser.user_id WHERE tFile.delete_flg = #{deleteFlg}
AND tFile.file_id IN (SELECT file_id FROM t_file WHERE title LIKE CONCAT('%', #{title}, '%') GROUP BY file_id)
AND tFile.file_id IN (SELECT file_id FROM t_file WHERE file_name LIKE CONCAT('%', #{fileName}, '%') GROUP BY file_id)
AND tFile.date >= #{dateFrom}
AND #{dateTo} >= tFile.date
AND tFile.date BETWEEN #{dateFrom} AND #{dateTo}
AND tFile.file_id IN (SELECT file_id FROM t_join_user WHERE user_id = #{userId} GROUP BY file_id)
AND tFile.file_id IN (SELECT file_id FROM t_file WHERE delete_flg = #{deleteFlg} AND REPLACE(REPLACE(convert_from(t_file.file, 'UTF8'), E'\r', ''), E'\n', '') LIKE CONCAT('%', #{findWord}, '%') AND t_file.file_name LIKE '%.txt' GROUP BY file_id)
ORDER BY tFile.date DESC,tFile.file_id ASC,tFile.serial_number ASC

mapper.update:
UPDATE t_file
SET delete_flg = #{deleteFlg},
    last_modified_date = #{lastModifiedDate},
    last_modified_user = #{lastModifiedUser},
    version = #{version} + 1
WHERE file_id = #{fileId}
    AND version = #{version}
    AND delete_flg != #{deleteFlg}

mapper.select:
SELECT tFile.file_name
FROM t_file tFile
WHERE tFile.delete_flg = #{deleteFlg}

AND tFile.file_id != #{fileId}
